sql:
SELECT pf_rank 
FROM personal_freedoms 
WHERE year = 2022;

SELECT pf_rank, year
FROM personal_freedoms
ORDER BY year DESC;

SELECT AVG(pf_score) AS average_pf_score
FROM personal_freedoms
WHERE year = 2022;

external_knowledge:
- "Overall freedom" refers to the combined average of personal freedom, economic freedom, and human freedom scores;
- The "top three nations" are determined by ranking countries based on the average of their freedom scores in descending order;
- "Combined average freedom scores" is the total average of personal freedom score, economic freedom score, and human freedom score.

sql:
SELECT c.country_name, il.income_level_name
FROM countries c
JOIN income_levels il ON c.income_level_id = il.income_level_id;

SELECT pf_score, pf_rank
FROM personal_freedoms
ORDER BY pf_rank DESC;

SELECT country_id, pf_score, pf_rank, year, pf_rank_change, pf_score_change
FROM personal_freedoms
WHERE year = (SELECT MAX(year) FROM personal_freedoms);

SELECT AVG(hf_score) AS average_human_freedom_score
FROM human_freedoms
WHERE year = 2022;
